DROP TABLE IF EXISTS `bc_order`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `bc_order` (
  `id` int NOT NULL AUTO_INCREMENT COMMENT 'ID',
  `uid` int NOT NULL COMMENT 'UID',
  `agent` int NOT NULL DEFAULT '0' COMMENT '代理人UID',
  `agents` int NOT NULL DEFAULT '0' COMMENT '总代理人UID',
  `orderid` varchar(32) NOT NULL COMMENT '订单号',
  `gameid` mediumint NOT NULL COMMENT '游戏ID',
  `qishu` varchar(15) NOT NULL COMMENT '期数',
  `money` decimal(10,2) NOT NULL COMMENT '订单金额',
  `account` decimal(10,2) NOT NULL COMMENT '结算',
  `wanfa` varchar(30) NOT NULL COMMENT '玩法',
  `addtime` int NOT NULL COMMENT '下单时间',
  `endtime` int NOT NULL COMMENT '结算时间',
  `tui` tinyint(1) NOT NULL COMMENT '是否退单1退单',
  `ban` tinyint(1) NOT NULL COMMENT '完成结算',
  PRIMARY KEY (`id`)
) ENGINE=MyISAM AUTO_INCREMENT=195 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
